            command.add("ping");
            command.add(getInputFromUser()); // Safe parameter passing

            ProcessBuilder processBuilder = new ProcessBuilder(command);
            Process process = processBuilder.start();
        } catch (IOException e) {
            e.printStackTrace();
        }
    }

    private static String getInputFromUser() {
        // Simulating user input, but this can be replaced with actual user input
        return "127.0.0.1"; // User input is not directly used in the command
